nodes.script:
setGlobal('kind', input.kind);
setGlobal('reasoning', input.reasoning);
setGlobal('summary', input.summary);
const runSocratic = input.shouldRunSocraticInterview === 'true';
input = input.summary;

setNodePath(runSocratic ? 'Interview' : 'Completed');

var interview = (context.interview || []).slice();
interview.push({ q: input.question, a: input.answer});
setContext('interview', interview);

setNodePath(input.decision);
